const form = document.getElementById('form');
const username = document.getElementById('username');
const email = document.getElementById('email');
const password = document.getElementById('password');

const usernameError = document.getElementById('username-error');
const emailError = document.getElementById('email-error');
const passwordError = document.getElementById('password-error');

function validateField(input, errorElement, isValid, message) {
  if (isValid) {
    input.classList.remove('border-slate-700', 'border-rose-500');
    input.classList.add('border-emerald-500');
    errorElement.classList.add('hidden');
  } else {
    input.classList.remove('border-slate-700', 'border-emerald-500');
    input.classList.add('border-rose-500');
    errorElement.textContent = message;
    errorElement.classList.remove('hidden');
  }
  return isValid;
}

form.addEventListener('submit', (e) => {
  e.preventDefault();

  const isUserValid = validateField(
    username,
    usernameError,
    username.value.trim().length >= 3,
    'Username must be at least 3 characters.'
  );

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = validateField(
    email,
    emailError,
    emailRegex.test(email.value.trim()),
    'Enter a valid email address.'
  );

  const passVal = password.value;
  const isPassLengthValid = passVal.length >= 8;
  const isPassHasNumber = /\d/.test(passVal);
  const isPassValid = validateField(
    password,
    passwordError,
    isPassLengthValid && isPassHasNumber,
    'Password must be 8+ characters and contain a number.'
  );

  if (isUserValid && isEmailValid && isPassValid) {
    alert('Form submitted successfully!');
  }
});
